import { ActionType } from "../../action/action-type";

const initialState = {

    // movies: [{
    //         name: "chocho",
    //         description: " Remember that you only need to do this for production builds. You shouldn’t pass the -p flag or apply this plugin in development, because it will hide useful React warnings and make the builds much slower."
    //     },
    //     {
    //         name: "sithu"

    //     }

    // ],

}


export const movieReducer = (state = initialState, { type, payload }) => {
    switch (type) {
        case ActionType.FETCH_MOVIES:
            return {...initialState, movie: payload };
        case ActionType.SELECT_MOVIE:
            return {...initialState, movie: payload };
        default:
            return state;

    }
}
